const e=JSON.parse('{"key":"v-5443a9a7","path":"/project/%E6%8A%A5%E4%BB%B7%E5%8D%95%E3%80%81%E4%BB%BB%E5%8A%A1%E5%8D%95%E3%80%81%E5%88%86%E6%9E%90%E5%8D%95%E7%AD%89%E7%B1%BBexecl%E8%A1%A8%E5%8D%95%E7%9A%84%E5%AE%9E%E7%8E%B0.html","title":"报价单、任务单、分析单等类execl表单的实现","lang":"zh-CN","frontmatter":{"title":"报价单、任务单、分析单等类execl表单的实现","isTimeLine":true,"date":"2026-03-03T00:00:00.000Z","category":["前端"],"tag":["JavaScript","node"]},"headers":[{"level":3,"title":"场景","slug":"场景","link":"#场景","children":[]},{"level":3,"title":"难点","slug":"难点","link":"#难点","children":[]},{"level":3,"title":"解决方案","slug":"解决方案","link":"#解决方案","children":[]},{"level":3,"title":"实现","slug":"实现","link":"#实现","children":[]},{"level":3,"title":"其他","slug":"其他","link":"#其他","children":[]}],"git":{"createdTime":1773506313000,"updatedTime":1773506313000,"contributors":[{"name":"liunal","email":"liunal","commits":1}]},"readingTime":{"minutes":3.34,"words":1002},"filePathRelative":"project/报价单、任务单、分析单等类execl表单的实现.md","localizedDate":"2026年3月3日","excerpt":"<h3> 场景</h3>\\n<ol>\\n<li>系统下达任务流程或者录入报价单时候，需要填很多信息。</li>\\n<li>报价单、任务单、分析单等表单希望跟填纸质单一样，直接在上面选填这次实验的委托信息、实验数据。</li>\\n</ol>\\n<h3> 难点</h3>\\n<ol>\\n<li>它的单元格就有多种形式。</li>\\n<li>如点击单元格出现下拉框展示计算单位、日期或者弹出弹窗选择公司、检测项目、检测方法、人员等。</li>\\n<li>这种选择可以减少错误率，比手写快速。</li>\\n</ol>\\n<h3> 解决方案</h3>\\n<ol>\\n<li>用了内部插件<code>fx-websheet</code>，是类<code>Excel</code>的自定义表单组件。它可以像<code>execl</code>一样有必填项校验、设置下拉框内容、复制粘贴。</li>\\n<li>它是通过在线<code>Excel</code>来设计表单布局以及边线样式后导出一个模板<code>json</code>，利用自定义组件<code>fx-websheet-widget</code>渲染对应位置的json模板来完成表单录入功能的一个产品.</li>\\n</ol>"}');export{e as data};
